    const [X, K] = lines[idx++].split(' ').map(Number);
    let left = 0, right = X;
    for (let j = 0; j < K - 1; j++) {
        const mid = Math.floor((left + right) / 2);
        if (mid - left > right - mid) {
            right = mid;
        } else {
            left = mid;
        }
    }
